1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface Policy {
7	  items: Item[];
8	  customer: { yearsWithMHPCO: number };
9	  isFollowUp: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
15	const DEFAULT_BASE_PREMIUM = 60;
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PREMIUM = 60;
19	
20	function countByType(items: Item[]): Record<string, number> {
21	  const counts: Record<string, number> = {};
22	  for (const item of items) {
23	    counts[item.type] = (counts[item.type] ?? 0) + 1;
24	  }
25	  return counts;
26	}
27	
28	function itemGroupPremium(type: string, count: number): number {
29	  if (count === BLOCK_SIZE) {
30	    return BLOCK_PREMIUM;
31	  }
32	  return count * (BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM);
33	}
34	
35	export function quote(policy: Policy) {
36	  const counts = countByType(policy.items);
37	
38	  let basePremium = 0;
39	  for (const [type, count] of Object.entries(counts)) {
40	    basePremium += itemGroupPremium(type, count);
41	  }
42	
43	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
44	  const premium = Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
45	  return { premium };
46	}
47	
48	export function claim() {
49	  return undefined;
50	}
